#include <stdio.h>
#include <string.h>
#include <ctype.h>

int is_alpha_str(const char *s) {
    while (*s) {
        if (!isalpha((unsigned char)*s)) return 0;
        s++;
    }
    return 1;
}

void trim(char *s) {
    // remove leading spaces
    char *start = s;
    while (isspace((unsigned char)*start)) start++;
    // remove trailing spaces
    char *end = start + strlen(start) - 1;
    while (end >= start && isspace((unsigned char)*end)) {
        *end = '\0';
        end--;
    }
    // shift trimmed string to beginning
    if (start != s) memmove(s, start, strlen(start) + 1);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char first[105], last[105];
        if (!fgets(first, sizeof(first), stdin)) break;
        if (!fgets(last, sizeof(last), stdin)) break;
        // remove trailing newline
        first[strcspn(first, "\n")] = '\0';
        last[strcspn(last, "\n")] = '\0';
        trim(first);
        trim(last);
        if (is_alpha_str(first) && is_alpha_str(last) && first[0] && last[0]) {
