#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(T):
        first = data[idx].strip() if idx < len(data) else ""
        idx += 1
        last = data[idx].strip() if idx < len(data) else ""
        idx += 1
        if first and last and first.isalpha() and last.isalpha():
            full = list(first) + list(last)
            out.append(f"Full name as a list of characters: {full}")
        else:
            out.append("Error: Please enter valid first and last names (letters only).")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

